const getLangInstruction = (): string => {
  const lang = i18n.getCurrentLanguage();
  switch (lang) {
    case 'en_US': return "Respond in English.";
    case 'ja_JP': return "Respond in Japanese.";
    case 'ko_KR': return "Respond in Korean.";
    default: return "Respond in Chinese (Simplified).";
  }
};

const getBaziMasterPrompt = (): string => {
  return `
