const LANG_MAP: Record<string, string> = {
  'zh': 'Simplified Chinese (简体中文)',
  // 'zh-TW': 'Traditional Chinese (繁體中文)',
  'en': 'English',
  'jp': 'Japanese (日本語)',
  'kr': 'Korean (한국어)',
  'de': 'German (Deutsch)',
  'fr': 'French (Français)',
  'es': 'Spanish (Español)'
};

const getLangName = (code: string) => LANG_MAP[code] || 'Simplified Chinese';

// --- HELPER: Robust JSON Extraction ---
const cleanJson = (text: string): string => {
  if (!text) return "{}";
  try {
    // Find the first '{' or '['
    const firstOpen = text.search(/[\{\[]/);
    // Find the last '}' or ']'
    const lastClose = text.search(/[\}\]][^\{\}\[\]]*$/);

    if (firstOpen !== -1 && lastClose !== -1 && lastClose >= firstOpen) {
      return text.substring(firstOpen, lastClose + 1);
    }
  } catch (e) {
    console.warn("JSON Cleaning failed, returning raw text", e);
  }
  return text.trim();
};

// Retry Helper
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> {
  try {
    return await fn();
  } catch (error: any) {
    const isRateLimit = 
      error?.status === 429 || 
      error?.code === 429 || 
      error?.message?.includes('429') || 
      error?.message?.includes('quota') ||
      error?.message?.includes('RESOURCE_EXHAUSTED') ||
      error?.error?.code === 429 ||
      error?.error?.status === 'RESOURCE_EXHAUSTED';

    if (retries > 0 && isRateLimit) {
      console.warn(`Gemini Quota Exceeded (429). Retrying in ${delay}ms... (${retries} left)`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
}

