    const weakest = sorted[0];
    const strongest = sorted[sorted.length - 1];
    const langName = getLangName(language);

    // STRENGTHENED PROMPT to force exactly 1 of each type
    const prompt = `
        Role: Life Coach.
        Language: **${langName} ONLY**.

        Task: Generate EXACTLY 3 "Life Cheat Cards" (Actionable Daily Items/Tasks) based on User Energy.
        **CRITICAL REQUIREMENT**: You MUST generate exactly ONE card for each of these 3 types: "prop", "consumable", "environment".

        Content: Grounded, realistic, daily life (e.g., coffee, headphones, subway). NO Abstract sci-fi.
        User Status: Weak(${weakest.name}), Strong(${strongest.name}).

        Output Schema (Array of 3 objects):
        [
          {
            "title": "String",
            "type": "prop", 
            "description": "String",
            "duration": "String",
            "effects": { "Wood": 10, "Fire": -5 },
            "triggerCondition": "String",
            "linkText": "String"
          },
          {
            "title": "String",
            "type": "consumable",
            ...
          },
          {
            "title": "String",
            "type": "environment",
            ...
          }
        ]
        `;

    const response = await retryWithBackoff<GenerateContentResponse>(() => ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        temperature: 0.9,
      }
    }));

    const text = cleanJson(response.text || "[]");
    let rawCards = JSON.parse(text);

    if (!Array.isArray(rawCards)) throw new Error("Invalid format");

    // Validation: Ensure we have at least 1 of each type, otherwise use fallback for missing ones
    const requiredTypes = ['prop', 'consumable', 'environment'];
    const validatedCards: any[] = [];
    const fallback = getFallbackCheats(language);

    requiredTypes.forEach(reqType => {
      const found = rawCards.find((c: any) => c.type === reqType);
      if (found) {
        validatedCards.push(found);
      } else {
        // If AI missed a type, grab from fallback
        const backup = fallback.find(c => c.type === reqType);
        if (backup) validatedCards.push(backup);
      }
    });

    return validatedCards.map((c: any, i: number) => ({
      id: `cheat-${Date.now()}-${i}`,
      ...c
    }));

  } catch (error) {
    console.warn("Cheat Sheet Gen Error:", error);
