const formatBigNumber = (val: number): string => {
    if (val >= 100000000) {
        return `¥ ${(val / 100000000).toFixed(2)}亿`;
    }
    return val.toLocaleString('zh-CN', {
        style: 'currency',
        currency: 'CNY',
        minimumFractionDigits: 2
    });
};

