const getLangInstruction = (lang: Language): string => {
    switch (lang) {
        // case 'zh-TW': return "Output in Traditional Chinese (繁體中文).";
        case 'en': return "Output in English.";
        case 'ja': return "Output in Japanese (日本語).";
        case 'ko': return "Output in Korean (한국어).";
        case 'de': return "Output in German (Deutsch).";
        case 'fr': return "Output in French (Français).";
        case 'es': return "Output in Spanish (Español).";
        default: return "Output in Simplified Chinese (简体中文).";
    }
};

/**
 * Helper: Retry with Exponential Backoff
 */
async function retryWithBackoff<T>(fn: () => Promise<T>, retries = 3, delay = 2000): Promise<T> {
    try {
        return await fn();
    } catch (error: any) {
        const isRateLimit = 
            error?.status === 429 || 
            error?.code === 429 || 
            error?.message?.includes('429') || 
            error?.message?.includes('quota') || 
            error?.status === 'RESOURCE_EXHAUSTED' ||
            error?.error?.code === 429 ||
            error?.error?.status === 'RESOURCE_EXHAUSTED';

        if (retries > 0 && isRateLimit) {
            console.warn(`Gemini API Rate Limit/Quota hit. Retrying in ${delay}ms... (${retries} left)`);
            await new Promise(resolve => setTimeout(resolve, delay));
            return retryWithBackoff(fn, retries - 1, delay * 2);
        }
        throw error;
    }
}

