const LANG_MAP: Record<string, string> = {
  'zh': 'Simplified Chinese (简体中文)',
  // 'zh-TW': 'Traditional Chinese (繁體中文)',
  'en': 'English',
  'jp': 'Japanese (日本語)',
  'kr': 'Korean (한국어)',
  'de': 'German (Deutsch)',
