    gender: (userProfile.gender === 'male' || userProfile.gender === 'female') ? userProfile.gender : 'neutral',
  } : {
    name: "Traveler",
    birthDate: new Date("2000-01-01"), // Default Date
    birthTime: "12:00",
    location: "Cosmos", // Mapped to Correct Interface Key
    gender: "neutral"
  };

  // Trigger Logic
  handleOnboardingComplete(profileData);
}, [userProfile, hasOnboarded]); // removed userData dep to avoid loops

