import React, { useState, useRef, useEffect } from 'react';
import { useLanguage } from '../contexts/LanguageContext';
import { Language } from '../types';
import { Globe, Check, ChevronDown } from 'lucide-react';

const LABELS: Record<Language, string> = {
  zh: '简体中文',
  'zh-TW': '繁體中文',
  en: 'English',
  ja: '日本語',
  ko: '한국어',
  de: 'Deutsch',
  fr: 'Français',
  es: 'Español'
};

interface Props {
  className?: string;
}

const LanguageSwitcher: React.FC<Props> = ({ className = "" }) => {
  const { language, setLanguage } = useLanguage();
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className={`relative z-50 ${className}`} ref={containerRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-black/40 border border-white/10 text-white/80 hover:bg-black/60 transition-all backdrop-blur-md"
      >
        <Globe size={14} className="text-indigo-400" />
        <span className="text-[10px] font-bold uppercase tracking-wider">{LABELS[language]}</span>
        <ChevronDown size={12} className={`transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 w-40 bg-[#1e202b] border border-white/10 rounded-xl shadow-xl overflow-hidden animate-slide-up-fade">
          <div className="max-h-64 overflow-y-auto py-1">
            {(Object.keys(LABELS) as Language[]).map((langKey) => (
              <button
                key={langKey}
                onClick={() => {
                  setLanguage(langKey);
                  setIsOpen(false);
                }}
                className="w-full text-left px-4 py-2.5 text-[11px] font-medium text-white/70 hover:bg-white/5 hover:text-white flex items-center justify-between transition-colors"
              >
                <span>{LABELS[langKey]}</span>
                {language === langKey && <Check size={12} className="text-emerald-400" />}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default LanguageSwitcher;

import React, { useState, useEffect, useRef } from 'react';
import { UserData, ElementType, ElementData, CheatCard, AstrologyData } from './types';
import Onboarding from './components/Onboarding';
import Dashboard from './components/Dashboard';
import LifeBook from './components/LifeBook';
import InstantInventory from './components/InstantInventory';
import CheatSheetSection from './components/CheatSheet';
import { TutorialOverlay } from './components/TutorialOverlay';
import ElementsScene from './components/ElementsScene';
import { generateLifeBook } from './utils/lifeBookGenerator';
import { getDailyEnergyLevels } from './utils/energyCalculator';
import { generateCheatCards } from './utils/gemini';
import { calculateAstrologyData } from './utils/astrologyEngine';
import { useI18n } from './utils/i18nContext';
import { ArrowLeft } from 'lucide-react';

interface AppProps {
  onBack?: () => void;
  userProfile?: {
    name: string;
    birthDate: string;
    birthTime: string;
    birthPlace: string;
    gender: string;
  };
}

const App: React.FC<AppProps> = ({ onBack, userProfile }) => {
  const { t, language } = useI18n();

  // --- STATE ---
  const [hasOnboarded, setHasOnboarded] = useState(false);
  const [userData, setUserData] = useState<UserData | null>(null);

  // Data State
  const [energyLevels, setEnergyLevels] = useState<Record<ElementType, number> | null>(null);
  const [elements, setElements] = useState<ElementData[]>([]);
  const [astrologyData, setAstrologyData] = useState<AstrologyData | undefined>(undefined);

  // UI State
  const [activeIndex, setActiveIndex] = useState(0);
  const [showDetail, setShowDetail] = useState(false);
  const [showLifeBook, setShowLifeBook] = useState(false);
  const [lifeBookData, setLifeBookData] = useState<any>(null);

  // Cheats State
  const [equippedCheats, setEquippedCheats] = useState<CheatCard[]>([]);
  const [availableCheats, setAvailableCheats] = useState<CheatCard[]>([]);

  // Tutorial
  const [showTutorial, setShowTutorial] = useState(false);

  // Scene Refs
  const dragOffset = useRef(0);

  // --- INITIALIZATION ---
  useEffect(() => {
    // If userProfile passed from main app, auto-onboard
    if (userProfile && !hasOnboarded) {
      const genderMap: Record<string, 'male' | 'female' | 'neutral'> = {
        'male': 'male', 'female': 'female', 'other': 'neutral'
      };

      const profileData: UserData = {
        name: userProfile.name,
        birthDate: new Date(userProfile.birthDate),
        birthTime: userProfile.birthTime || "12:00",
        location: userProfile.birthPlace || "Unknown",
        gender: genderMap[userProfile.gender] || 'neutral'
      };

      handleOnboardingComplete(profileData);
    }
  }, [userProfile]);

  const initData = async (data: UserData) => {
    // 1. Calculate Astrology Base
    const astro = calculateAstrologyData(data);
    setAstrologyData(astro);

    // 2. Calculate Daily Energy (with randomness seed)
    const levels = getDailyEnergyLevels(data);
    setEnergyLevels(levels);

    // 3. Format for Scene
    const formattedElements: ElementData[] = [
      { type: ElementType.Wood, name: t('Wood') || 'Wood', trait: 'Growth', description: 'Creativity & Expansion', percentage: levels[ElementType.Wood], color: '#4ade80', position: [-4, 0, 0] },
      { type: ElementType.Fire, name: t('Fire') || 'Fire', trait: 'Passion', description: 'Action & Visibility', percentage: levels[ElementType.Fire], color: '#f87171', position: [-2, 0, 0] },
      { type: ElementType.Earth, name: t('Earth') || 'Earth', trait: 'Stability', description: 'Trust & Foundation', percentage: levels[ElementType.Earth], color: '#d6d3d1', position: [0, 0, 0] },
      { type: ElementType.Metal, name: t('Metal') || 'Metal', trait: 'Order', description: 'Logic & Discipline', percentage: levels[ElementType.Metal], color: '#facc15', position: [2, 0, 0] },
      { type: ElementType.Water, name: t('Water') || 'Water', trait: 'Wisdom', description: 'Flow & Emotion', percentage: levels[ElementType.Water], color: '#60a5fa', position: [4, 0, 0] },
    ];
    setElements(formattedElements);
    setActiveIndex(2); // Start at Earth (Center)

    // 4. Generate Cheats
    const cheats = await generateCheatCards(formattedElements, language);
    setAvailableCheats(cheats);

    // 5. Generate Life Book (Async)
    generateLifeBook(data, language).then(setLifeBookData);
  };

  const handleOnboardingComplete = (data: UserData) => {
    setUserData(data);
    setHasOnboarded(true);
    initData(data);

    // Show tutorial for new users
    const visited = localStorage.getItem('lb_visited');
    if (!visited) {
       setTimeout(() => setShowTutorial(true), 1000);
       localStorage.setItem('lb_visited', 'true');
    }
  };

  // --- ACTIONS ---

  const handleUpdateEnergy = (delta: Partial<Record<ElementType, number>>, resetTarget = false) => {
    if (!energyLevels) return;

    const newLevels = { ...energyLevels };
    if (resetTarget) {
         // Reset scenario (e.g. overload fix)
         Object.keys(delta).forEach(k => {
             const key = k as ElementType;
             newLevels[key] = 60; // Reset to healthy baseline
         });
    } else {
        Object.entries(delta).forEach(([k, v]) => {
            const key = k as ElementType;
            newLevels[key] = Math.min(100, Math.max(0, newLevels[key] + (v as number)));
        });
    }

    setEnergyLevels(newLevels);

    // Update Elements for Visuals
    setElements(prev => prev.map(el => ({
        ...el,
        percentage: newLevels[el.type]
    })));
  };

  const handleEquipCheat = (card: CheatCard) => {
      // 1. Apply Effect
      handleUpdateEnergy(card.effects);
      // 2. Move to Equipped
      setEquippedCheats(prev => [...prev, card]);
  };

  const handleUnequipCheat = (id: string) => {
      const card = equippedCheats.find(c => c.id === id);
      if (card) {
          // Reverse Effect
          const reverseEffect: any = {};
          Object.entries(card.effects).forEach(([k, v]) => {
              reverseEffect[k] = -(v as number);
          });
          handleUpdateEnergy(reverseEffect);
          setEquippedCheats(prev => prev.filter(c => c.id !== id));
      }
  };

  const handleRefreshCheats = async () => {
      if (elements.length > 0) {
        const cheats = await generateCheatCards(elements, language);
        setAvailableCheats(cheats);
      }
  };

  const handleReset = () => {
      localStorage.clear(); // Clear all app data
      window.location.reload();
  };

  // --- RENDER ---

  if (!hasOnboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  return (
    <div className="relative w-full h-full bg-[#050505] text-white overflow-hidden font-sans">

        {/* BACK BUTTON */}
        {onBack && (
            <button 
                onClick={onBack}
                className="absolute top-6 left-6 z-[60] w-10 h-10 flex items-center justify-center bg-black/20 backdrop-blur-md rounded-full border border-white/10 text-white/70 hover:text-white hover:bg-white/10 transition-all active:scale-95"
            >
                <ArrowLeft size={20} />
            </button>
        )}

        {/* 3D SCENE BACKGROUND */}
        <ElementsScene 
            elements={elements} 
            activeIndex={activeIndex} 
            dragOffset={dragOffset}
            onSelect={(idx) => setActiveIndex(idx)}
        />

        {/* TUTORIAL */}
        {showTutorial && <TutorialOverlay onComplete={() => setShowTutorial(false)} />}

        {/* MAIN DASHBOARD UI */}
        <div className="absolute inset-0 flex flex-col pointer-events-none">

            {/* Top Area & HUDs */}
            <div className="flex-1 relative">
                <Dashboard 
                    activeElement={elements[activeIndex]}
                    onNext={() => setActiveIndex((i) => (i + 1) % elements.length)}
                    onPrev={() => setActiveIndex((i) => (i - 1 + elements.length) % elements.length)}
                    showDetail={showDetail}
                    onOpenDetail={() => setShowDetail(true)}
                    onCloseDetail={() => setShowDetail(false)}
                    onOpenLifeBook={() => setShowLifeBook(true)}
                    onOpenCheatSheet={() => {}} // Legacy
                    activeCheats={equippedCheats}
                    onUnequipCheat={handleUnequipCheat}
                    astrologyData={astrologyData}
                    onUpdateEnergy={handleUpdateEnergy}
                    userName={userData?.name}
                />
            </div>

            {/* Scrollable Bottom Area (Inventory & Cheats) */}
            <div className="h-[45vh] pointer-events-auto overflow-y-auto no-scrollbar mask-gradient-top relative z-10 pb-20">
                <div className="pt-20">
                    {/* Module 1: Inventory */}
                    {energyLevels && (
                        <InstantInventory 
                            energyLevels={energyLevels} 
                            onUpdateEnergy={handleUpdateEnergy} 
                            isInvalidUser={astrologyData?.isValid === false}
                        />
                    )}

                    {/* Module 2: Cheat Sheet */}
                    <CheatSheetSection 
                        cards={availableCheats} 
                        onEquip={handleEquipCheat} 
                        onUnequip={handleUnequipCheat}
                        equippedCardIds={equippedCheats.map(c => c.id)}
                        onRefresh={handleRefreshCheats}
                    />
                </div>
            </div>
        </div>

        {/* LIFE BOOK MODAL */}
        {lifeBookData && (
            <LifeBook 
                data={lifeBookData} 
                isOpen={showLifeBook} 
                onClose={() => setShowLifeBook(false)} 
                onReset={handleReset}
            />
        )}

    </div>
  );
};

export default App;
